function slWlQuote(age,male,smoker,tier,face){
  if(age<50||age>85)return null;
  const tbl=male?SL_WL_M:SL_WL_F;
  const td=tbl[tier];if(!td)return null;
  const r=td[age];if(!r)return null;
  let bps,minF,maxF;
  if(tier==='B'){bps=[10000,15000,20000,25000,30000];minF=10000;maxF=30000;}
  else if(tier==='C'){bps=[2000,5000,10000,15000,20000];minF=2000;maxF=20000;}
  else if(tier==='D'){bps=[2000,5000,10000,15000];minF=2000;maxF=15000;}
  else if(tier==='E'){bps=[2000,5000,10000];minF=2000;maxF=10000;}
  else return null;
  const f=Math.max(minF,Math.min(maxF,face));
  if(f<=bps[0])return Math.round(r[0]*100)/100;
  if(f>=bps[bps.length-1])return Math.round(r[r.length-1]*100)/100;
  for(let i=0;i<bps.length-1;i++){
    if(f>=bps[i]&&f<=bps[i+1]){
      const t=(f-bps[i])/(bps[i+1]-bps[i]);
      return Math.round((r[i]+t*(r[i+1]-r[i]))*100)/100;
    }
  }
  return null;
}

