function fidQuote(tbl,age,male,smoker,face){const row=tbl[age];if(!row)return null;const ri=male?(smoker?1:0):(smoker?3:2);return Math.round((row[ri]*face/1000+85)*0.087*100)/100;}

// CSV rate_per_1k values are already monthly premiums (modal already baked in by source)
// Formula: rate_per_1k × face/1000 + policy_fee
// Fallback order: exact ri → same gender/other tobacco → other gender → any available
function csvLookup(tbl, _modal, age, male, smoker, face) {
  const row = tbl[age];
  if (!row) return null;
  const ri = (male ? 0 : 2) + (smoker ? 1 : 0);
  const fallbacks = [ri, ri ^ 1, ri ^ 2, ri ^ 3];
  for (const tryRi of fallbacks) {
    const entry = row[tryRi];
    if (entry) return Math.round((entry[0] * face / 1000 + entry[1]) * 100) / 100;
  }
  return null;
}

